import React from 'react';
import Hero from '../components/Hero';
import JobCard from '../components/JobCard';
import useFetchJobs from '../hooks/useFetchJobs';

const HomePage = () => {
  const { jobs, loading, error } = useFetchJobs();

  if (loading) return <div className="flex justify-center items-center h-64">Loading...</div>;
  if (error) return <div className="flex justify-center items-center h-64">Error loading jobs</div>;

  return (
    <div>
      <Hero 
        title="Find Your Dream Job"
        subtitle="Search from thousands of job listings and find the perfect fit for you."
        ctaLabel="Get Started"
        onCta={() => console.log('CTA Clicked')}
      />
      <section className="py-16 bg-gray-900">
        <div className="max-w-6xl mx-auto px-4">
          <h2 className="text-2xl font-semibold text-white mb-2">Featured Jobs</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
            {(jobs ?? []).map(job => (
              <JobCard key={job.id} job={job} />
            ))}
          </div>
        </div>
      </section>
    </div>
  );
};

export default HomePage;

