import React from 'react';
import { useParams } from 'react-router-dom';
import LoadingSpinner from '../components/LoadingSpinner';

const JobDetailPage = () => {
  const { jobId } = useParams();
  const [job, setJob] = React.useState(null);
  const [loading, setLoading] = React.useState(true);

  React.useEffect(() => {
    // Fetch job details from API
    fetch(`/api/jobs/${jobId}`)
      .then(response => response.json())
      .then(data => {
        setJob(data);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [jobId]);

  if (loading) return <LoadingSpinner />;
  if (!job) return <div className="text-center text-white">Job not found</div>;

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold text-white mb-4">{job?.title ?? 'Job Title'}</h1>
      <p className="text-gray-400 mb-4">{job?.description ?? 'Job Description'}</p>
      <div className="flex justify-between items-center">
        <span className="text-gray-400">Location: {job?.location ?? 'Unknown'}</span>
        <span className="text-gray-400">Salary: {job?.salary ?? 'N/A'}</span>
      </div>
      <button className="mt-6 px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">
        Apply Now
      </button>
    </div>
  );
};

export default JobDetailPage;
